    public void FormatPhoneNumber_ValidDigits_EndsWithLastFour()
    {
        var result = _formatter.FormatPhoneNumber("2125551234");
        StringAssert.EndsWith(result, "1234");
    }

    [TestMethod]
    public void FormatPhoneNumber_ValidDigits_ContainsDash()
    {
        var result = _formatter.FormatPhoneNumber("2125551234");
        StringAssert.Contains(result, "-");
    }

    [TestMethod]
    public void FormatPhoneNumber_ValidDigits_ReturnsFullFormat()
    {
        var result = _formatter.FormatPhoneNumber("2125551234");
        Assert.AreEqual("(212) 555-1234", result);
    }

    [TestMethod]
    [ExpectedException(typeof(ArgumentNullException))]
    public void FormatPhoneNumber_Null_ThrowsArgumentNullException()
    {
        _formatter.FormatPhoneNumber(null!);
    }

    [TestMethod]
    [ExpectedException(typeof(ArgumentException))]
    public void FormatPhoneNumber_WrongLength_ThrowsArgumentException()
    {
        _formatter.FormatPhoneNumber("123");
    }

    // ── BuildGreeting ──────────────────────────────────────────────

    [TestMethod]
    public void BuildGreeting_DefaultTitle_StartsWithDearMr()
    {
        var result = _formatter.BuildGreeting("Smith");
        StringAssert.StartsWith(result, "Dear Mr.");
    }

    [TestMethod]
    public void BuildGreeting_DefaultTitle_EndsWithComma()
    {
        var result = _formatter.BuildGreeting("Smith");
        StringAssert.EndsWith(result, ",");
    }

    [TestMethod]
    public void BuildGreeting_DefaultTitle_ContainsName()
    {
        var result = _formatter.BuildGreeting("Smith");
        StringAssert.Contains(result, "Smith");
    }

    [TestMethod]
    public void BuildGreeting_CustomTitle_UsesProvidedTitle()
    {
        var result = _formatter.BuildGreeting("Johnson", "Dr.");
        StringAssert.StartsWith(result, "Dear Dr.");
        Assert.AreEqual("Dear Dr. Johnson,", result);
    }

    [TestMethod]
    [ExpectedException(typeof(ArgumentException))]
    public void BuildGreeting_WhitespaceName_ThrowsArgumentException()
    {
        _formatter.BuildGreeting("   ");
    }

    // ── GenerateSlug ───────────────────────────────────────────────

    [TestMethod]
    public void GenerateSlug_SimpleTitle_ReturnsLowercaseDashed()
    {
        var result = _formatter.GenerateSlug("Hello World");
        Assert.AreEqual("hello-world", result);
    }

    [TestMethod]
    public void GenerateSlug_SpecialCharacters_ReplacesWithDashes()
    {
        var result = _formatter.GenerateSlug("C# is great!!!");
        StringAssert.StartsWith(result, "c-");
        StringAssert.EndsWith(result, "great");
    }

    [TestMethod]
    public void GenerateSlug_LeadingTrailingSpaces_TrimsCleanly()
    {
        var result = _formatter.GenerateSlug("  Some Title  ");
        Assert.AreEqual("some-title", result);
    }

    [TestMethod]
    public void GenerateSlug_MultipleSpaces_CollapsesToSingleDash()
    {
        var result = _formatter.GenerateSlug("one   two   three");
        Assert.AreEqual("one-two-three", result);
    }

    [TestMethod]
    public void GenerateSlug_Result_MatchesSlugPattern()
    {
        var result = _formatter.GenerateSlug("My Blog Post Title!");
        StringAssert.Matches(result, new System.Text.RegularExpressions.Regex(@"^[a-z0-9]+(-[a-z0-9]+)*$"));
    }

    [TestMethod]
    [ExpectedException(typeof(ArgumentException))]
    public void GenerateSlug_WhitespaceOnly_ThrowsArgumentException()
    {
        _formatter.GenerateSlug("   ");
    }

    // ── FormatCurrency ─────────────────────────────────────────────

    [TestMethod]
    public void FormatCurrency_DefaultSymbol_StartsWithDollar()
    {
        var result = _formatter.FormatCurrency(19.99m);
        StringAssert.StartsWith(result, "$");
    }

    [TestMethod]
    public void FormatCurrency_DefaultSymbol_EndsWithTwoDecimals()
    {
        var result = _formatter.FormatCurrency(19.9m);
        StringAssert.EndsWith(result, ".90");
    }

    [TestMethod]
    public void FormatCurrency_CustomSymbol_StartsWithSymbol()
    {
        var result = _formatter.FormatCurrency(100m, "€");
        StringAssert.StartsWith(result, "€");
    }

    [TestMethod]
    public void FormatCurrency_WholeNumber_FormatsWithDecimals()
    {
        var result = _formatter.FormatCurrency(42m);
        Assert.AreEqual("$42.00", result);
    }

    [TestMethod]
    public void FormatCurrency_NegativeAmount_ContainsMinus()
    {
        var result = _formatter.FormatCurrency(-5.50m);
        StringAssert.Contains(result, "-");
    }
}

